"""Lesson data 51-55"""
from src.tts import M, F

L51={"num":51,"intro_es":"Μάθημα πεντήκοντα ἕν. Lección cincuenta y uno. Hoy aprenderás sobre enviar, recibir, y la misión. Escucha.",
"dialogue":[(M,"Καθὼς ἀπέσταλκέν με ὁ πατήρ, κἀγὼ πέμπω ὑμᾶς."),(F,"Λάβετε πνεῦμα ἅγιον.")],
"context_es":"Como el Padre me envió, yo también los envío a ustedes. Reciban el Espíritu Santo.",
"vocab":[{"gr":"ἀποστέλλω","es":"enviar con misión","note_es":"ἀποστέλλω significa enviar con una misión. Viene de ἀπό y στέλλω. De aquí viene apóstol. Aparece ciento treinta y dos veces. Escucha."},{"gr":"πέμπω","es":"enviar","note_es":"πέμπω significa enviar. Es más general que ἀποστέλλω. Aparece setenta y nueve veces. Escucha."},{"gr":"δέχομαι","es":"recibir, aceptar","note_es":"δέχομαι significa recibir o aceptar. Es deponente. Aparece cincuenta y seis veces. Escucha."},{"gr":"ἀποκαλύπτω","es":"revelar","note_es":"ἀποκαλύπτω significa revelar. Viene de ἀπό, lejos, y καλύπτω, cubrir. Quitar la cubierta. De aquí viene Apocalipsis. Escucha."},{"gr":"μαρτυρέω","es":"testificar, dar testimonio","note_es":"μαρτυρέω significa testificar. De aquí viene mártir. Aparece setenta y seis veces. Escucha."},{"gr":"μαρτυρία","es":"testimonio","note_es":"μαρτυρία significa testimonio. Aparece treinta y siete veces. Escucha."}],
"phrases":[{"gr":"ἀπέσταλκέν με ὁ πατήρ","es":"el Padre me envió","prompt_es":"Di el Padre me envió."},{"gr":"κἀγὼ πέμπω ὑμᾶς","es":"yo también los envío","prompt_es":"Di yo también los envío."},{"gr":"λάβετε πνεῦμα ἅγιον","es":"reciban el Espíritu Santo","prompt_es":"Di reciban el Espíritu Santo."},{"gr":"μαρτυρεῖτε περὶ ἐμοῦ","es":"testifiquen acerca de mí","prompt_es":"Di testifiquen acerca de mí."},{"gr":"ἀπεκάλυψεν ἡμῖν","es":"nos reveló","prompt_es":"Di nos reveló."},{"gr":"ἡ μαρτυρία αὐτοῦ ἀληθής ἐστιν","es":"su testimonio es verdadero","prompt_es":"Di su testimonio es verdadero."}],
"recon":[{"prompt_es":"Di como el Padre me envió, yo también los envío.","answer_gr":"Καθὼς ἀπέσταλκέν με ὁ πατήρ, κἀγὼ πέμπω ὑμᾶς.","answer_voice":M},{"prompt_es":"Di reciban el Espíritu Santo.","answer_gr":"Λάβετε πνεῦμα ἅγιον.","answer_voice":M}],
"verse":{"gr":"Καθὼς ἀπέσταλκέν με ὁ πατήρ, κἀγὼ πέμπω ὑμᾶς.","voice":M,"ref_es":"Juan veinte veintiuno:","explain_es":"Como el Padre me envió, yo también los envío. καθώς, como. ἀπέσταλκεν, ha enviado, perfecto. πέμπω, envío."},
"closing_es":"Aprendiste sobre misión: ἀποστέλλω enviar, πέμπω enviar, δέχομαι recibir, ἀποκαλύπτω revelar, μαρτυρέω testificar. Εἰρήνη σοι."}

L52={"num":52,"intro_es":"Μάθημα πεντήκοντα δύο. Lección cincuenta y dos. Hoy aprenderás sobre la resurrección y la vida después de la muerte. Escucha.",
"dialogue":[(M,"Ἐγώ εἰμι ἡ ἀνάστασις καὶ ἡ ζωή."),(F,"Ἠγέρθη, οὐκ ἔστιν ὧδε."),(M,"Εἰ Χριστὸς οὐκ ἐγήγερται, κενὸν τὸ κήρυγμα ἡμῶν.")],
"context_es":"Yo soy la resurrección y la vida. Ha resucitado, no está aquí. Si Cristo no ha resucitado, vana es nuestra predicación.",
"vocab":[{"gr":"ἀνάστασις","es":"resurrección","note_es":"ἀνάστασις significa resurrección. Viene de ἀνά, arriba, y ἵστημι, poner de pie. Ponerse de pie de nuevo. Aparece cuarenta y dos veces. Escucha."},{"gr":"νεκρός","es":"muerto","note_es":"νεκρός significa muerto. Aparece ciento veintiocho veces. οἱ νεκροί, los muertos. ἐκ νεκρῶν, de entre los muertos. Escucha."},{"gr":"ἐγήγερται","es":"ha resucitado (perfecto)","note_es":"ἐγήγερται es el perfecto pasivo de ἐγείρω. Significa ha sido levantado, ha resucitado. El perfecto indica un estado presente resultado de una acción pasada. Escucha."},{"gr":"κενός","es":"vacío, vano","note_es":"κενός significa vacío o vano. Escucha."},{"gr":"κήρυγμα","es":"predicación, proclamación","note_es":"κήρυγμα significa predicación. Viene de κηρύσσω, predicar. El sufijo μα indica resultado: lo que resulta de predicar. Escucha."},{"gr":"θάπτω","es":"sepultar","note_es":"θάπτω significa sepultar. ἐτάφη es fue sepultado. Escucha."}],
"phrases":[{"gr":"ἀνάστασις νεκρῶν","es":"resurrección de muertos","prompt_es":"Di resurrección de muertos."},{"gr":"ἠγέρθη ἐκ νεκρῶν","es":"resucitó de entre los muertos","prompt_es":"Di resucitó de entre los muertos."},{"gr":"Χριστὸς ἐγήγερται","es":"Cristo ha resucitado","prompt_es":"Di Cristo ha resucitado."},{"gr":"ἀπέθανεν καὶ ἐτάφη καὶ ἐγήγερται","es":"murió, fue sepultado y ha resucitado","prompt_es":"Di murió, fue sepultado y ha resucitado."},{"gr":"ζωὴ αἰώνιος","es":"vida eterna","prompt_es":"Di vida eterna."},{"gr":"ἐγώ εἰμι ἡ ἀνάστασις","es":"yo soy la resurrección","prompt_es":"Di yo soy la resurrección."}],
"recon":[{"prompt_es":"Di Cristo ha resucitado.","answer_gr":"Χριστὸς ἐγήγερται.","answer_voice":M},{"prompt_es":"Di resucitó de entre los muertos.","answer_gr":"Ἠγέρθη ἐκ νεκρῶν.","answer_voice":M},{"prompt_es":"Di yo soy la resurrección y la vida.","answer_gr":"Ἐγώ εἰμι ἡ ἀνάστασις καὶ ἡ ζωή.","answer_voice":M}],
"verse":{"gr":"Εἰ δὲ Χριστὸς οὐκ ἐγήγερται, κενὸν ἄρα τὸ κήρυγμα ἡμῶν.","voice":M,"ref_es":"Primera de Corintios quince catorce:","explain_es":"Si Cristo no ha resucitado, vana es nuestra predicación. εἰ, si. ἐγήγερται, ha resucitado. κενόν, vana. κήρυγμα, predicación."},
"closing_es":"Aprendiste sobre resurrección: ἀνάστασις resurrección, νεκρός muerto, ἐγήγερται ha resucitado, κήρυγμα predicación. Εἰρήνη σοι."}

L53={"num":53,"intro_es":"Μάθημα πεντήκοντα τρία. Lección cincuenta y tres. Hoy aprenderás metáforas joánicas: la vid, el pastor, la puerta. Escucha.",
"dialogue":[(M,"Ἐγώ εἰμι ἡ ἄμπελος ἡ ἀληθινή."),(M,"Ἐγώ εἰμι ὁ ποιμὴν ὁ καλός."),(M,"Ἐγώ εἰμι ἡ θύρα.")],
"context_es":"Yo soy la vid verdadera. Yo soy el buen pastor. Yo soy la puerta. Las declaraciones Yo Soy de Jesús en el evangelio de Juan.",
"vocab":[{"gr":"ἄμπελος","es":"vid","note_es":"ἄμπελος significa vid. ἡ ἄμπελος, la vid. Jesús dijo: yo soy la vid verdadera. Escucha."},{"gr":"κλῆμα","es":"rama, sarmiento","note_es":"κλῆμα significa rama o sarmiento de la vid. ὑμεῖς τὰ κλήματα, ustedes son las ramas. Escucha."},{"gr":"ποιμήν","es":"pastor","note_es":"ποιμήν significa pastor. Aparece dieciocho veces. ὁ ποιμὴν ὁ καλός, el buen pastor. Escucha."},{"gr":"ἀρνίον","es":"cordero","note_es":"ἀρνίον significa cordero. Aparece treinta veces, especialmente en Apocalipsis. Escucha."},{"gr":"πρόβατον","es":"oveja","note_es":"πρόβατον significa oveja. Viene de πρό, adelante, y βαίνω, caminar. Originalmente cualquier cuadrúpedo. Aparece treinta y nueve veces. Escucha."},{"gr":"μένω","es":"permanecer","note_es":"Ya conoces μένω, permanecer. Jesús dice: permanezcan en mí como la rama en la vid. Escucha."}],
"phrases":[{"gr":"ἐγώ εἰμι ἡ ἄμπελος ἡ ἀληθινή","es":"yo soy la vid verdadera","prompt_es":"Di yo soy la vid verdadera."},{"gr":"ἐγώ εἰμι ὁ ποιμὴν ὁ καλός","es":"yo soy el buen pastor","prompt_es":"Di yo soy el buen pastor."},{"gr":"ὁ ποιμὴν ὁ καλὸς τὴν ψυχὴν αὐτοῦ τίθησιν ὑπὲρ τῶν προβάτων","es":"el buen pastor da su vida por las ovejas","prompt_es":"Di el buen pastor da su vida por las ovejas. τίθησιν significa pone."},{"gr":"ἐγώ εἰμι ἡ θύρα","es":"yo soy la puerta","prompt_es":"Di yo soy la puerta."},{"gr":"μείνατε ἐν ἐμοί","es":"permanezcan en mí","prompt_es":"Di permanezcan en mí."},{"gr":"τὸ ἀρνίον τοῦ θεοῦ","es":"el cordero de Dios","prompt_es":"Di el cordero de Dios."}],
"recon":[{"prompt_es":"Di yo soy la vid verdadera.","answer_gr":"Ἐγώ εἰμι ἡ ἄμπελος ἡ ἀληθινή.","answer_voice":M},{"prompt_es":"Di yo soy el buen pastor.","answer_gr":"Ἐγώ εἰμι ὁ ποιμὴν ὁ καλός.","answer_voice":M},{"prompt_es":"Di el cordero de Dios.","answer_gr":"Τὸ ἀρνίον τοῦ θεοῦ.","answer_voice":M}],
"verse":{"gr":"Ἐγώ εἰμι ἡ ὁδὸς καὶ ἡ ἀλήθεια καὶ ἡ ζωή.","voice":M,"ref_es":"Juan catorce seis:","explain_es":"Yo soy el camino, la verdad y la vida. ὁδός, camino. ἀλήθεια, verdad. ζωή, vida. Tres palabras que ya conoces perfectamente."},
"closing_es":"Aprendiste metáforas joánicas: ἄμπελος vid, ποιμήν pastor, ἀρνίον cordero, πρόβατον oveja. Y las declaraciones Yo Soy de Jesús. Εἰρήνη σοι."}

L54={"num":54,"intro_es":"Μάθημα πεντήκοντα τέσσαρα. Lección cincuenta y cuatro. Hoy aprenderás sobre la ley, los profetas, y las escrituras. Escucha.",
"dialogue":[(M,"Μὴ νομίσητε ὅτι ἦλθον καταλῦσαι τὸν νόμον ἢ τοὺς προφήτας· οὐκ ἦλθον καταλῦσαι ἀλλὰ πληρῶσαι.")],
"context_es":"No piensen que vine a abolir la ley o los profetas. No vine a abolir sino a cumplir.",
"vocab":[{"gr":"προφήτης","es":"profeta","note_es":"προφήτης significa profeta. Viene de πρό, delante, y φημί, hablar. El que habla delante, el portavoz. Aparece ciento cuarenta y cuatro veces. Escucha."},{"gr":"πληρόω","es":"cumplir, llenar","note_es":"πληρόω significa cumplir o llenar. πληρῶσαι es cumplir, infinitivo aoristo. Aparece ochenta y seis veces. Escucha."},{"gr":"καταλύω","es":"destruir, abolir","note_es":"καταλύω significa destruir o abolir. Viene de κατά, abajo, y λύω, soltar. Soltar abajo, derribar. Escucha."},{"gr":"πλήρωμα","es":"plenitud, cumplimiento","note_es":"πλήρωμα significa plenitud. Viene de πληρόω. El sufijo μα indica resultado. Escucha."},{"gr":"ἐπαγγελία","es":"promesa","note_es":"ἐπαγγελία significa promesa. Aparece cincuenta y dos veces. Escucha."},{"gr":"διαθήκη","es":"pacto, testamento","note_es":"διαθήκη significa pacto o testamento. Viene de διά y τίθημι. La raíz θηκ es de τίθημι, poner. Aparece treinta y tres veces. Escucha."}],
"phrases":[{"gr":"ὁ νόμος καὶ οἱ προφῆται","es":"la ley y los profetas","prompt_es":"Di la ley y los profetas."},{"gr":"οὐκ ἦλθον καταλῦσαι ἀλλὰ πληρῶσαι","es":"no vine a abolir sino a cumplir","prompt_es":"Di no vine a abolir sino a cumplir."},{"gr":"ἡ καινὴ διαθήκη","es":"el nuevo pacto","prompt_es":"Di el nuevo pacto. καινή significa nuevo."},{"gr":"αἱ ἐπαγγελίαι τοῦ θεοῦ","es":"las promesas de Dios","prompt_es":"Di las promesas de Dios."},{"gr":"τὸ πλήρωμα τοῦ χρόνου","es":"la plenitud del tiempo","prompt_es":"Di la plenitud del tiempo."},{"gr":"γέγραπται ἐν τοῖς προφήταις","es":"está escrito en los profetas","prompt_es":"Di está escrito en los profetas."}],
"recon":[{"prompt_es":"Di no vine a abolir la ley sino a cumplir.","answer_gr":"Οὐκ ἦλθον καταλῦσαι τὸν νόμον ἀλλὰ πληρῶσαι.","answer_voice":M},{"prompt_es":"Di el nuevo pacto.","answer_gr":"Ἡ καινὴ διαθήκη.","answer_voice":M},{"prompt_es":"Di las promesas de Dios.","answer_gr":"Αἱ ἐπαγγελίαι τοῦ θεοῦ.","answer_voice":M}],
"verse":{"gr":"Μὴ νομίσητε ὅτι ἦλθον καταλῦσαι τὸν νόμον ἢ τοὺς προφήτας· οὐκ ἦλθον καταλῦσαι ἀλλὰ πληρῶσαι.","voice":M,"ref_es":"Mateo cinco diecisiete:","explain_es":"No piensen que vine a abolir la ley o los profetas. No vine a abolir sino a cumplir. νομίσητε, piensen. ἦλθον, vine. καταλῦσαι, abolir. πληρῶσαι, cumplir."},
"closing_es":"Aprendiste sobre escrituras: προφήτης profeta, πληρόω cumplir, καταλύω abolir, διαθήκη pacto, ἐπαγγελία promesa. Εἰρήνη σοι."}

L55={"num":55,"intro_es":"Μάθημα πεντήκοντα πέντε. Lección cincuenta y cinco. Hoy aprenderás sobre el Espíritu Santo y Pentecostés. Escucha.",
"dialogue":[(M,"Λήμψεσθε δύναμιν ἐπελθόντος τοῦ ἁγίου πνεύματος ἐφ᾽ ὑμᾶς."),(F,"Καὶ ἔσεσθέ μου μάρτυρες.")],
"context_es":"Recibirán poder cuando el Espíritu Santo venga sobre ustedes. Y serán mis testigos.",
"vocab":[{"gr":"δύναμις","es":"poder, capacidad","note_es":"δύναμις significa poder o capacidad. Aparece ciento diecinueve veces. De aquí viene dinámico y dinamita. Escucha."},{"gr":"μάρτυς","es":"testigo","note_es":"μάρτυς significa testigo. De aquí viene mártir. Aparece treinta y cinco veces. Escucha."},{"gr":"γλῶσσα","es":"lengua, idioma","note_es":"γλῶσσα significa lengua o idioma. En Pentecostés hablaron en otras lenguas. Escucha."},{"gr":"πλήρης","es":"lleno","note_es":"πλήρης significa lleno. πλήρης πνεύματος ἁγίου, lleno del Espíritu Santo. Escucha."},{"gr":"ἐπέρχομαι","es":"venir sobre","note_es":"ἐπέρχομαι significa venir sobre. Viene de ἐπί, sobre, y ἔρχομαι. Escucha."},{"gr":"πῦρ","es":"fuego","note_es":"πῦρ significa fuego. Aparece setenta y una veces. γλῶσσαι ὡσεὶ πυρός, lenguas como de fuego. Escucha."}],
"phrases":[{"gr":"λήμψεσθε δύναμιν","es":"recibirán poder","prompt_es":"Di recibirán poder."},{"gr":"ἔσεσθέ μου μάρτυρες","es":"serán mis testigos","prompt_es":"Di serán mis testigos."},{"gr":"πλήρεις πνεύματος ἁγίου","es":"llenos del Espíritu Santo","prompt_es":"Di llenos del Espíritu Santo."},{"gr":"ἐλάλουν ἑτέραις γλώσσαις","es":"hablaban en otras lenguas","prompt_es":"Di hablaban en otras lenguas."},{"gr":"γλῶσσαι ὡσεὶ πυρός","es":"lenguas como de fuego","prompt_es":"Di lenguas como de fuego."},{"gr":"ἡ δύναμις τοῦ θεοῦ","es":"el poder de Dios","prompt_es":"Di el poder de Dios."}],
"recon":[{"prompt_es":"Di recibirán poder cuando el Espíritu Santo venga sobre ustedes.","answer_gr":"Λήμψεσθε δύναμιν ἐπελθόντος τοῦ ἁγίου πνεύματος ἐφ᾽ ὑμᾶς.","answer_voice":M},{"prompt_es":"Di serán mis testigos.","answer_gr":"Ἔσεσθέ μου μάρτυρες.","answer_voice":M},{"prompt_es":"Di el poder de Dios.","answer_gr":"Ἡ δύναμις τοῦ θεοῦ.","answer_voice":M}],
"verse":{"gr":"Λήμψεσθε δύναμιν ἐπελθόντος τοῦ ἁγίου πνεύματος ἐφ᾽ ὑμᾶς, καὶ ἔσεσθέ μου μάρτυρες.","voice":M,"ref_es":"Hechos uno ocho:","explain_es":"Recibirán poder cuando el Espíritu Santo venga sobre ustedes, y serán mis testigos. λήμψεσθε, recibirán. δύναμιν, poder. μάρτυρες, testigos."},
"closing_es":"Aprendiste sobre el Espíritu: δύναμις poder, μάρτυς testigo, γλῶσσα lengua, πλήρης lleno, πῦρ fuego. Εἰρήνη σοι."}
